// Получаем даты за прошлую неделю
const now = new Date();
const weekAgo = new Date();
weekAgo.setDate(now.getDate() - 7);

const formatDate = (d) => d.toISOString().split('T')[0];

return [{
  json: {
    week_start: formatDate(weekAgo),
    week_end: formatDate(now),
    cutoff_timestamp: weekAgo.toISOString(),
    page: 1
  }
}];

// OmniDesk возвращает: {"0": {"case": {...}}, "1": {...}}
const response = $input.first().json;
const prevData = $('Set Date Range').first().json;
const cutoffDate = new Date(prevData.cutoff_timestamp);

// Проверяем на Cloudflare/ошибки
if (typeof response === 'string' || response.error) {
  throw new Error('API Error: ' + JSON.stringify(response));
}

// Конвертируем объект с числовыми ключами в массив
const keys = Object.keys(response).filter(k => !isNaN(parseInt(k)));
const tickets = [];

for (const key of keys) {
  const caseData = response[key].case || response[key];

  let createdAt;
  try {
    createdAt = new Date(caseData.created_at);
  } catch (e) {
    continue;
  }

  // Фильтруем по дате (только за последние 7 дней)
  if (createdAt >= cutoffDate) {
    tickets.push({
      ticket_id: caseData.case_id,
      created_at: caseData.created_at,
      closed_at: caseData.closed_at !== '-' ? caseData.closed_at : null,
      status: caseData.status,
      priority: caseData.priority,
      channel: caseData.channel,
      subject: caseData.subject,
      labels: caseData.labels || [],
      closing_speed: caseData.closing_speed !== '-' ? parseInt(caseData.closing_speed) : null
    });
  }
}

console.log(`Found ${tickets.length} tickets from last 7 days`);

// Возвращаем каждый тикет как отдельный item
return tickets.map(ticket => ({ json: ticket }));

const ticket = $('Loop Through Tickets').first().json;
const resp = $input.first().json;

// Handle access error
if (resp?.error === 'staff_has_not_access' || resp?.statusCode === 403) {
  return [{
    json: {
      ticket_id: parseInt(ticket.ticket_id),
      created_at: parseDate(ticket.created_at),
      closed_at: parseDate(ticket.closed_at),
      status: ticket.status || null,
      priority: ticket.priority || null,
      channel: ticket.channel || null,
      subject: ticket.subject || null,
      first_message_text: null,
      labels: (ticket.labels && ticket.labels.length > 0) ? ticket.labels : null,
      closing_speed: ticket.closing_speed ? parseInt(ticket.closing_speed) : null
    }
  }];
}

// Parse dates to ISO format
function parseDate(dateStr) {
  if (!dateStr || dateStr === '-') return null;
  try {
    return new Date(dateStr).toISOString();
  } catch {
    return null;
  }
}

// OmniDesk returns numeric keys: {"0": {"message": {...}}, ...}
const numericKeys = Object.keys(resp || {}).filter(k => !isNaN(parseInt(k, 10)));
const raw = numericKeys
  .map(k => resp[k]?.message || resp[k])
  .filter(Boolean);

// Select first CUSTOMER message, fallback to first message overall
const sortByCreated = (a, b) => new Date(a.created_at) - new Date(b.created_at);

const customer = raw
  .filter(m => Number(m.staff_id ?? 0) === 0 && Boolean(m.note) === false)
  .sort(sortByCreated);

let first = customer[0];

if (!first) {
  raw.sort(sortByCreated);
  first = raw[0] || null;
}

let text = first ? (first.content || first.content_html || null) : null;

// Cleanup HTML
function stripHtml(s) {
  if (!s) return null;
  return String(s)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim()
    .slice(0, 5000);
}

// Return ONLY fields that exist in Supabase table
return [{
  json: {
    ticket_id: parseInt(ticket.ticket_id),
    created_at: parseDate(ticket.created_at),
    closed_at: parseDate(ticket.closed_at),
    status: ticket.status || null,
    priority: ticket.priority || null,
    channel: ticket.channel || null,
    subject: ticket.subject || null,
    first_message_text: stripHtml(text),
    labels: (ticket.labels && ticket.labels.length > 0) ? ticket.labels : null,
    closing_speed: ticket.closing_speed ? parseInt(ticket.closing_speed) : null
  }
}];

const tickets = $input.all().map(item => item.json);

const now = new Date();
const weekAgo = new Date();
weekAgo.setDate(now.getDate() - 7);

const inputData = {
  week_start_date: weekAgo.toISOString().split('T')[0],
  week_end_date: now.toISOString().split('T')[0],
  tickets: tickets.map(t => ({
    ticket_id: String(t.ticket_id),
    created_at: t.created_at,
    closed_at: t.closed_at,
    status: t.status,
    priority: t.priority,
    channel: t.channel,
    subject: t.subject,
    first_message_text: t.first_message_text,
    labels: t.labels,
    closing_speed: t.closing_speed
  }))
};

return [{
  json: {
    ticketCount: tickets.length,
    inputJson: JSON.stringify(inputData)
  }
}];

const inputJson = $input.first().json.inputJson;

const systemPrompt = `You are "Weekly Support Insights Analyst" for MetaShip.

Analyze the provided support tickets and produce a JSON report with:
1) Executive summary (one_liner + key_stats + top_issues)
2) Top 3 risks with evidence ticket_ids
3) Issue clusters by problem types
4) Top clients by ticket volume
5) Product and ops recommendations

HARD RULES:
1) No hallucinations. Only use data from input.
2) Every risk/insight MUST cite at least 3 ticket_ids for medium+ severity.
3) Redact PII (phone/email) as "[REDACTED]".
4) Output ONLY valid JSON, no markdown code blocks.
5) Set all delta fields to "insufficient_data".

CLUSTER KEYS:
- delivery_point_not_found
- order_creation_validation_errors  
- api_integration_questions
- status_sync_issues
- bitrix_module_issues
- tariff_calculation_errors

SEVERITY: critical > high > medium > low

OUTPUT JSON SCHEMA:
{
  "report_metadata": {"week_start_date": "", "week_end_date": "", "total_tickets_analyzed": 0},
  "executive_summary": {
    "one_liner": "",
    "key_stats": {"total_tickets": 0, "closed_tickets": 0, "open_tickets": 0},
    "top_issues": []
  },
  "top_3_risks": [{
    "title": "",
    "severity": "high",
    "confidence": 0.8,
    "evidence_ticket_ids": [],
    "delta_vs_last_week": "insufficient_data"
  }],
  "insights": [{
    "metric_key": "",
    "title": "",
    "ticket_count": 0,
    "severity": "medium",
    "evidence_ticket_ids": []
  }],
  "top_clients_analysis": {
    "clients": [{"client_name": "", "ticket_count": 0}]
  },
  "limitations": ["No historical data for trends"]
}

Respond with ONLY the JSON.`;

return [{
  json: {
    systemPrompt: systemPrompt,
    userMessage: 'Analyze these support tickets:\n\n' + inputJson
  }
}];

const response = $input.first().json;

let content = response.message?.content || response.choices?.[0]?.message?.content || '';

let report;
try {
  // Remove markdown code blocks if present
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  report = JSON.parse(content);
} catch (e) {
  return [{
    json: {
      error: 'Failed to parse AI response: ' + e.message,
      raw_content: content.substring(0, 1000)
    }
  }];
}

return [{
  json: {
    report: report,
    generated_at: new Date().toISOString()
  }
}];

const data = $input.first().json;

if (data.error) {
  return [{
    json: {
      telegram_message: `❌ *Error generating report*\n\n${data.error}\n\nRaw: ${data.raw_content?.substring(0, 200) || 'N/A'}`,
      has_error: true
    }
  }];
}

const report = data.report;
const meta = report.report_metadata || {};
const summary = report.executive_summary || {};
const risks = report.top_3_risks || [];
const clients = report.top_clients_analysis?.clients || [];

let message = `📊 *Weekly Support Report*
📅 ${meta.week_start_date || 'N/A'} — ${meta.week_end_date || 'N/A'}

💡 *Summary:* ${summary.one_liner || 'N/A'}

📈 *Key Stats:*
• Total tickets: ${summary.key_stats?.total_tickets || meta.total_tickets_analyzed || 'N/A'}
• Closed: ${summary.key_stats?.closed_tickets || 'N/A'}
• Open: ${summary.key_stats?.open_tickets || 'N/A'}

🚨 *Top 3 Risks:*
`;

risks.forEach((risk, i) => {
  const emoji = risk.severity === 'critical' ? '🔴' : risk.severity === 'high' ? '🟠' : '🟡';
  message += `${i+1}. ${emoji} *${risk.title}* (${risk.severity})\n`;
});

if (clients.length > 0) {
  message += `\n👥 *Top Clients:*\n`;
  clients.slice(0, 5).forEach((c, i) => {
    message += `${i+1}. ${c.client_name}: ${c.ticket_count} tickets\n`;
  });
}

if (summary.top_issues && summary.top_issues.length > 0) {
  message += `\n📋 *Top Issues:*\n`;
  summary.top_issues.slice(0, 5).forEach((issue) => {
    message += `• ${issue}\n`;
  });
}

message += `\n_Generated: ${data.generated_at}_`;

return [{
  json: {
    telegram_message: message,
    full_report: report,
    has_error: false
  }
}];
